import React, { useState, useEffect } from 'react';
import Navbar from '../../components/common/Navbar';
import Sidebar from '../../components/common/Sidebar';
import Loader from '../../components/common/Loader';
import { getStudentRecommendations } from '../../services/api';

const Recommendations = () => {
  const userName = localStorage.getItem('userName') || 'Student';
  const userId = localStorage.getItem('userId');
  const [loading, setLoading] = useState(true);
  const [recommendations, setRecommendations] = useState([]);

  useEffect(() => {
    fetchRecommendations();
  }, []);

  const fetchRecommendations = async () => {
    try {
      const response = await getStudentRecommendations(userId);
      setRecommendations(response.data.recommendations || []);
    } catch (error) {
      console.error('Error fetching recommendations:', error);
      setRecommendations([]);
    } finally {
      setLoading(false);
    }
  };

  if (loading) {
    return (
      <div className="min-h-screen galaxy-bg">
        <Navbar role="Student" userName={userName} />
        <div className="flex">
          <Sidebar role="student" />
          <main className="flex-1">
            <Loader />
          </main>
        </div>
      </div>
    );
  }

  const getPriorityColor = (priority) => {
    switch (priority) {
      case 'High': return 'border-red-500 bg-red-900 bg-opacity-20';
      case 'Medium': return 'border-yellow-500 bg-yellow-900 bg-opacity-20';
      case 'Low': return 'border-blue-500 bg-blue-900 bg-opacity-20';
      case 'Info': return 'border-green-500 bg-green-900 bg-opacity-20';
      default: return 'border-gray-500 bg-gray-900 bg-opacity-20';
    }
  };

  return (
    <div className="min-h-screen galaxy-bg">
      <Navbar role="Student" userName={userName} />
      <div className="flex">
        <Sidebar role="student" />
        <main className="flex-1 p-6">
          <h2 className="text-3xl font-bold text-white mb-6">Recommendations 💡</h2>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            {recommendations.length > 0 ? (
              recommendations.map((rec, index) => (
                <div
                  key={index}
                  className={`rounded-xl shadow-lg p-6 border-l-4 ${getPriorityColor(rec.priority)} hover:shadow-2xl transition transform hover:scale-105`}
                >
                  <div className="flex items-start space-x-4">
                    <div className="text-4xl">{rec.icon}</div>
                    <div className="flex-1">
                      <div className="flex justify-between items-start mb-2">
                        <h3 className="text-lg font-bold text-white">{rec.title}</h3>
                        <span className={`text-xs px-2 py-1 rounded-full font-semibold ${
                          rec.priority === 'High' ? 'bg-red-600 text-white' :
                          rec.priority === 'Medium' ? 'bg-yellow-600 text-white' :
                          rec.priority === 'Low' ? 'bg-blue-600 text-white' :
                          'bg-green-600 text-white'
                        }`}>
                          {rec.priority}
                        </span>
                      </div>
                      <p className="text-gray-300 text-sm">{rec.description}</p>
                      <div className="mt-3">
                        <span className="text-xs text-gray-400 bg-white bg-opacity-10 px-2 py-1 rounded">
                          {rec.type}
                        </span>
                      </div>
                    </div>
                  </div>
                </div>
              ))
            ) : (
              <div className="col-span-2 text-center text-gray-400 py-12">
                No recommendations available yet. Keep practicing!
              </div>
            )}
          </div>
        </main>
      </div>
    </div>
  );
};

export default Recommendations;
